const CookSlide = ({callBackContent}) => {
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(()=>{
    callBackContent(newImgs[0].content);
  },[])

  const nextHandler = () => {
    if (currentIndex === newImgs.length - 1) {
      setCurrentIndex(0);
      callBackContent(newImgs[0].content);
    } else {
      setCurrentIndex(currentIndex + 1);
      callBackContent(newImgs[currentIndex + 1].content);
    }
  };

  const prenHandler = () => {
    if (currentIndex === 0) {
      setCurrentIndex(newImgs.length - 1);
      callBackContent(newImgs[newImgs.length - 1].content);
    } else {
      setCurrentIndex(currentIndex - 1);
      callBackContent(newImgs[currentIndex -1].content);
      
    }
  };

  const currentSlide = newImgs[currentIndex];

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '100%'}}>
      <img src={currentSlide.src} alt={currentSlide.altText} style={{ width: '100%', objectFit: 'cover' }} />
      <div style={{ display: 'flex', justifyContent: 'center', marginTop: '1rem' }}>
        <div style={{ padding: '10px', margin: '0 10px' }} onClick={prenHandler}>
          <FiArrowLeft  />
        </div>
        <span style={{ paddingTop: '10px'}}>{currentIndex + 1}/{newImgs.length }</span>
        <div style={{ padding: '10px', margin: '0 10px' }} onClick={nextHandler}>
          <FiArrowRight  />
        </div>
      </div>
    </div>
  );
};

export default CookSlide;




