import { useState } from 'react';
import { FiArrowLeft } from "react-icons/fi";
import { FiArrowRight } from "react-icons/fi";

const images = [
  { key: 1, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq1.png`, caption: 'slide1', altText: 'slide1' },
  { key: 2, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq2.PNG`, caption: 'slide2', altText: 'slide2' },
  { key: 3, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq3.PNG`, caption: 'slide3', altText: 'slide3' },
  { key: 4, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq4.PNG`, caption: 'slide4', altText: 'slide4' },
  { key: 5, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq5.PNG`, caption: 'slide5', altText: 'slide5' },
  { key: 6, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq6.PNG`, caption: 'slide6', altText: 'slide6' },
  { key: 7, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq7.PNG`, caption: 'slide7', altText: 'slide7' },
  { key: 8, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq8.PNG`, caption: 'slide8', altText: 'slide8' },
  { key: 9, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq9.PNG`, caption: 'slide9', altText: 'slide9' },
  { key: 10, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq10.PNG`, caption: 'slide10', altText: 'slide10' },
  { key: 11, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq11.PNG`, caption: 'slide11', altText: 'slide11' },
  { key: 12, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq12.PNG`, caption: 'slide12', altText: 'slide12' },
  { key: 13, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq13.PNG`, caption: 'slide13', altText: 'slide13' },
  { key: 14, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq14.PNG`, caption: 'slide14', altText: 'slide14' },
  { key: 15, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq15.PNG`, caption: 'slide15', altText: 'slide15' },
  { key: 16, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq16.PNG`, caption: 'slide16', altText: 'slide16' },
  { key: 17, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq17.PNG`, caption: 'slide17', altText: 'slide17' },
  { key: 18, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq18.PNG`, caption: 'slide18', altText: 'slide18' },
  { key: 19, src: `${process.env.PUBLIC_URL}/Cookcrew/Teq/teq19.PNG`, caption: 'slide19', altText: 'slide19' }
]

const CookTeq = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const nextHandler = () => {
    if (currentIndex === images.length - 1) {
      setCurrentIndex(0);
    } else {
      setCurrentIndex(currentIndex + 1);
    }
  };

  const prenHandler = () => {
    if (currentIndex === 0) {
      setCurrentIndex(images.length - 1);
    } else {
      setCurrentIndex(currentIndex - 1);
    }
  };

  const currentSlide = images[currentIndex];

  return (
    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '100%' }}>
      <img src={currentSlide.src} alt={currentSlide.altText} style={{ width: '100%', objectFit: 'cover' }} />
      <div style={{ display: 'flex', justifyContent: 'center', marginTop: '1rem' }}>
        <div>
          <FiArrowLeft onClick={prenHandler} />
        </div>
        <span style={{ margin: '0 1rem' }}>{currentIndex + 1}/{images.length + 1}</span>
        <div>
          <FiArrowRight onClick={nextHandler} />
        </div>
      </div>
    </div>
  );
};

export default CookTeq;