import React from 'react';
import { useState } from 'react';
import { Link } from 'react-scroll';

import headerNav from '../Css/headerNav.css'

const HeaderNav = () => {

    return (
        <div>
        <div id='scroll_wrapper'>
            <div id='link_70container'>
                <div id='link_50container_left'>
                    <Link
                        //to 에 div id
                        activeClass="active"
                        to="linkTop"
                        spy={true}
                        smooth={true}
                        duration={500}               >
                        <b>PortFolio Home</b>
                    </Link>
                </div>
                <div id='link_50container_right'>
                    <div id='to_link_item'>
                        <Link
                            //to 에 div id
                            activeClass="active"
                            to="linkAboutMe"
                            spy={true}
                            smooth={true}
                            duration={500}               >
                            WhoAmI
                        </Link>
                    </div>
                    <div id='to_link_item'>
                        <Link
                            //to 에 div id
                            activeClass="active"
                            to="linkProject"
                            spy={true}
                            smooth={true}
                            duration={500}               >
                            Project
                        </Link>
                    </div>
                    <div id='to_link_item'>
                        <Link
                            //to 에 div id
                            activeClass="active"
                            to="linkCertificate"
                            spy={true}
                            smooth={true}
                            duration={500}               >
                            Certificate
                        </Link>
                    </div>
    
                </div>
            </div>
        </div>
        </div>
    );
};

export default HeaderNav;