
import CookSlide from "../Component/CookSlide"
import CookTeq from "../Component/CookTeq"
import { MdOutlineChangeCircle } from "react-icons/md";
import { useState } from 'react';

import project from "../Css/project.css"
import P_cookcrew from "./P_cookcrew";
import P_gangchew from "./P_gangchew";



export default function Project() {
    const [slide, setSlide] = useState(0);
    const slideHandler = () => {
        setSlide(slide === 0 ? 1 : 0);
    }


    return (
        <div style={{ backgroundColor: '#7480BA', height: 'auto' }}>
            <div style={{ height: '5rem', backgroundColor: 'white' }}></div>
            <div id="project_top">
                <div id="project_title">
                    <p style={{ fontSize: '60px', textAlign: 'center',color:'white' }}><b>Project</b></p>
                    <P_cookcrew/>
                    <P_gangchew/>
                </div>
            </div>
            <div style={{ height: '50px' }} />
        </div>
    )
}